// Load a video at the top-left corner, start playing immediately
StelVideoMgr.loadVideo("/path/to/video.mp4", "intro", 0, 0, true, 1.0);

// Load a video centered on screen (relative positioning), but don't play yet
StelVideoMgr.loadVideo("/path/to/video.mp4", "centered", 0.5, 0.5, false, 1.0);

// Load a video at absolute pixel coordinates
StelVideoMgr.loadVideo("/path/to/video.mp4", "topRight", 1280, 0, false, 0.8);

// Play a video normally
StelVideoMgr.playVideo("intro");

// Play a video and keep the last frame visible on screen
StelVideoMgr.playVideo("intro", true);

// Resume a paused video
StelVideoMgr.playVideo("intro");

// Popout from the center of the screen to full size
var screenW = core.getScreenWidth();
var screenH = core.getScreenHeight();
StelVideoMgr.playVideoPopout("intro", screenW/2, screenH/2, screenW/2, screenH/2, screenW, screenH, 1.5, false);

// Popout from a corner, grow to a specific size, and freeze during transition
StelVideoMgr.playVideoPopout("intro", 0, 0, 0.5, 0.5, 800, 600, 2.0, true);

// Popout with relative positioning and auto-scaling
StelVideoMgr.playVideoPopout("intro", 0.1, 0.1, 0.5, 0.5, -1, 0.6, 1.5, false);

// Pause the video
StelVideoMgr.pauseVideo("intro");

// Resume playback later
StelVideoMgr.playVideo("intro");

// Stop the video (window closes)
StelVideoMgr.stopVideo("intro");

// Play from the beginning
StelVideoMgr.playVideo("intro");

// Jump to 30 seconds and pause
StelVideoMgr.seekVideo("intro", 30000, true);

// Jump to 1 minute and continue playing
StelVideoMgr.seekVideo("intro", 60000, false);

// Move to absolute pixel coordinates
StelVideoMgr.setVideoXY("intro", 100, 100, false);

// Move 50 pixels right and 20 pixels up from the current position
StelVideoMgr.setVideoXY("intro", 50, -20, true);

// Center the video on the screen
var screenW = core.getScreenWidth();
var videoW = StelVideoMgr.getVideoWidth("intro");
StelVideoMgr.setVideoXY("intro", (screenW - videoW) / 2, 0, false);

// Make the video semi-transparent (Qt6 only)
StelVideoMgr.setVideoAlpha("intro", 0.5);

// Fully opaque
StelVideoMgr.setVideoAlpha("intro", 1.0);

// Fully transparent (invisible)
StelVideoMgr.setVideoAlpha("intro", 0.0);

// Resize to full screen (relative)
StelVideoMgr.resizeVideo("intro", 1.0, 1.0);

// Resize to half the screen size
StelVideoMgr.resizeVideo("intro", 0.5, 0.5);

// Resize to specific pixel dimensions (may distort)
StelVideoMgr.resizeVideo("intro", 640, 480);

// Auto-scale to a width of 800 pixels, maintaining aspect ratio
StelVideoMgr.resizeVideo("intro", 800, -1);

// Auto-scale to a height of 600 pixels, maintaining aspect ratio
StelVideoMgr.resizeVideo("intro", -1, 600);

// Hide the video window
StelVideoMgr.showVideo("intro", false);

// Show it again
StelVideoMgr.showVideo("intro", true);

// Play the video first, then get its duration
StelVideoMgr.playVideo("intro");
var duration = StelVideoMgr.getVideoDuration("intro");
if (duration > 0) {
    core.debug("Video duration: " + (duration / 1000).toFixed(1) + " seconds");
} else {
    core.debug("Duration not yet available.");
}

var pos = StelVideoMgr.getVideoPosition("intro");
if (pos >= 0) {
    core.debug("Current position: " + (pos / 1000).toFixed(1) + " seconds");
}

StelVideoMgr.playVideo("intro");
var resolution = StelVideoMgr.getVideoResolution("intro");
if (resolution.isValid()) {
    core.debug("Native resolution: " + resolution.width() + "x" + resolution.height());
}

var width = StelVideoMgr.getVideoWidth("intro");
if (width > 0) {
    core.debug("Video width: " + width);
}

// Mute the video's sound
StelVideoMgr.muteVideo("intro", true);

// Unmute
StelVideoMgr.muteVideo("intro", false);

// Set volume to 75%
StelVideoMgr.setVideoVolume("intro", 75);

// Mute the audio
StelVideoMgr.setVideoVolume("intro", 0);

// Maximum volume
StelVideoMgr.setVideoVolume("intro", 100);

var volume = StelVideoMgr.getVideoVolume("intro");
if (volume >= 0) {
    core.debug("Current volume: " + volume + "%");
}

if (StelVideoMgr.isVideoPlaying("intro")) {
    core.debug("The video is currently playing.");
} else {
    core.debug("The video is not playing (paused, stopped, or not loaded).");
}
